var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"형님들~ 들으셨습니까?","JPN":"みんな、聞きましたか？","ENG":"Did y'all hear the news?","TWN":"兄弟們~ 聽到了嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"지금 3종 침식체가 이쪽으로 오고 있다는데요.","JPN":"今、第3種侵食体がこっちに向かっているらしいです。","ENG":"There's a Category 3 headed our way.","TWN":"現在3類侵蝕體正在向這邊移動。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"3종 침식체요......? 그거 엄청 위험한 놈 아닙니까?","JPN":"第3種侵食体ですか……？　あれ、相当危険な奴じゃないですか？","ENG":"Category 3? Isn't that super dangerous?","TWN":"3類侵蝕體……？那不是非常危險的傢伙嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"그렇지. 혼자서 도시 하나 박살낼 만큼 인정사정 안 봐 주는 녀석이야.","JPN":"そうだな。単体で都市1つを壊滅できるくらい、容赦のない奴だ。","ENG":"It sure is. Those things are brutal enough to destroy an entire city by themselves.","TWN":"對。單單一個就能將整個城市夷為平地。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"그, 그럼 한가하게 떠들 때가 아니잖습니까! 정말 큰일이잖아요!","JPN":"ってことは、今ここでのんびりしている場合ではないじゃないですか！　本当にヤバいんじゃないですか！","ENG":"Th-then we don't have time to lounge around like this! We're in some serious trouble here!","TWN":"那、那該怎麼辦！這情況太糟了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"......형님.","JPN":"……兄貴。","ENG":"Sir.","TWN":"……大哥。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"나도 들었어.","JPN":"聞こえたぞ。","ENG":"I heard.","TWN":"我也聽到了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"어쩌실 겁니까?","JPN":"どうしましょうか？","ENG":"What should we do?","TWN":"你打算怎麼辦？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"3종 침식체라면 A급 카운터에 준하는 전력이 있어야 붙어 볼 만할 겁니다.","JPN":"第3種侵食体ならAランクカウンターに準ずる戦力がないと手に負えないでしょう。","ENG":"We'll need at least a Grade A Counter to stand a chance against a Category 3.","TWN":"要對付3類侵蝕體，至少需要有與A級制裁者同等戰力才能與之抗衡。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"녀석 주위에 우글거릴 다른 하급 침식체들까지 생각하면, 저희 전력만으로는......","JPN":"奴らの周辺に大量にいる下級侵食体のことまで考えると、我々の戦力だけでは……","ENG":"Not to mention all those lesser C.O.s swarming about... We simply don't have the firepower.","TWN":"如果再加上其他低階種類的侵蝕體，只靠我們的戰力恐怕……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"그렇다고 도망칠 수는 없지.","JPN":"だからって逃げるわけにはいかん。","ENG":"But we can't just flee either.","TWN":"那也不能逃跑吧。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"이 뒤는 민간인 거주지역이야. 우리가 내빼면 그곳 시민들은 도망칠 틈도 없이 침식체들에게 당한다.","JPN":"この先は民間人居住地域だ。我々が逃げたら、そこの住民たちは逃げる間もなく侵食体にやられる。","ENG":"There are civilian residences behind us. If we bail, the C.O.s will get to them before they even get a chance to evacuate.","TWN":"我們身後就是居民區。如果我們退縮，這裡的市民們就會受到侵蝕體攻擊，根本沒地方逃跑。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"하지만 이런 데서 목숨을 날릴 멍청이가 많을 필요도 없겠지.","JPN":"だがこんな所で全員死ぬ必要はないだろう。","ENG":"But it doesn't necessarily mean we need to sacrifice the lives of our all troops here.","TWN":"但是也沒必要把整個小隊葬送在這裡。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"넌 젊은 녀석들 데리고 후방으로 가라.","JPN":"お前は若い奴らを連れて後方に行け。","ENG":"You take the younger guys and fall back to the rear.","TWN":"你帶著年輕隊員先撤退到後方。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"여긴 늙은이들이 버텨 볼 테니까.","JPN":"ここは老いぼれで何とか時間を稼いでみる。","ENG":"We old-timers will try to fend them off here.","TWN":"我們這些老人會幫你們爭取時間。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"하, 늙어서 치매라도 왔습니까? 닭살 돋는 소리 마십쇼.","JPN":"は？　とうとうボケてきたんですか？　聞いてられませんね。","ENG":"Hah, you going senile in your old age? Surely you don't expect us to go along with that crap.","TWN":"啊，大哥你不是老年癡呆了吧？別說這麼肉麻的話，好不好。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"우리도 침식체 놈들 앞에서 줄행랑이나 치려고 이 빌어먹을 강화복 걸친 게 아닙니다.","JPN":"私たちだって侵食体を前にして逃げるために、こんなクソ重い強化服を纏ったんじゃないです。","ENG":"We're not wearing these freaking power suits just so we can turn tail and run from C.O.s.","TWN":"我們穿上這身強化服，可不是為了看到侵蝕體就夾起尾巴逃跑。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"그러니 형님은 방패나 잘 들고 계십쇼.","JPN":"だから、兄貴はその盾さえしっかり構えてくれりゃいい。","ENG":"So keep holding your shield nice and sturdy.","TWN":"所以，大哥你要拿穩盾牌。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"3종이든 뭐든 그놈 머리통은 제 샷건으로 날려 버릴 테니까.","JPN":"第3種でもなんでも、奴の脳みそはこのショットガンでぶち抜いてやりますから。","ENG":"I'll blow away any Category 3's with my shotgun.","TWN":"不管是3類還是什麼，我們一起把它腦殼打爆。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"니들도 들었지? 여긴 노인네들이 맡을 테니까 너흰 빨리 후퇴 준비를......","JPN":"お前ら聞いたか？　ここはジジイたちに任せてお前らは退却の準備を……","ENG":"Did you hear that, boys? We've got this here. You guys prepare to retreat—","TWN":"你們也聽到了吧？這裡由我們這幫老人負責，你們趕快做好撤退準備……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"하하, 농담도 잘하십니다.","JPN":"ハハハ、冗談が過ぎますよ。","ENG":"Hah hah, you must be kidding.","TWN":"哈哈，別開玩笑了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L32_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"블랙 타이드는 돌격도 같이, 퇴각도 같이 아닙니까?","JPN":"ブラックタイドは突撃も退却も共に、がモットーです。","ENG":"We're the Black Tide. We attack together and retreat together.","TWN":"黑潮是一體的，不管是突擊還是撤退都要一起才對。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"말이 나와서 말인데 저도 그거 한 번 해 보고 싶었습니다.","JPN":"一度言ってみたかった言葉があります。","ENG":"Speaking of which, I've always wanted to say this.","TWN":"話說回來，我其實只是想試試看而已。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"<b>가장 먼저 들어가서 가장 마지막에 나와 드리지, 설명이 더 필요하시오?</b>","JPN":"<b>真っ先に突入し、一番最後に出てこよう。これ以上の説明が必要かね？</b>","ENG":"<b>I always go in first and come out last. Need more explanation?</b>","TWN":"<b>第一個進戰場，最後一個出戰場。還需要再說別的嗎？</b>"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"어떻습니까? 좀 비슷하지 않습니까?","JPN":"どうです？　ちょっと似てるでしょう？","ENG":"What do you think? Don't I sound just like you?","TWN":"怎麼樣？是不是很像？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"하나도 안 비슷한데요. 완전 안 어울려요.","JPN":"全然似てませんね。似合わないし。","ENG":"Not at all. You just sound cheesy.","TWN":"一點都不像，跟你的形象都不搭。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"놀지 말고 참호나 빨리 쌓으세요. 모래주머니 아직 많이 남았습니다.","JPN":"のんびりしてないではやく塹壕を掘ってください。砂袋がまだこんなに残っていますよ。","ENG":"Stop fooling around and help me set up this barricade. There are still lots of sandbags lying around.","TWN":"別偷懶，快搭建戰壕。還剩那麼多沙袋呢。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"허 참. 요즘 신입들은 낭만을 몰라, 낭만을.","JPN":"やれやれ、最近の若者はロマンを知らないんだな。","ENG":"Oh, come on. You youngsters just don't know what's cool.","TWN":"哎，真是。現在的新人都不懂得浪漫。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"......하여간 이놈이나 저놈이나 멍청이들만 모여서는.","JPN":"……どいつもこいつもアホばかり集まってきやがって。","ENG":"You're all just a bunch of idiots.","TWN":"……你們一個一個，怎麼都這麼笨呢。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"좋아. 채리엇으로 길 막고 방어선 구축해.","JPN":"いいだろう。チャリオットで道を塞いで防御線を作れ。","ENG":"Very well. Blockade the path with the Chariot and form a defensive line.","TWN":"算了。先用部戰車封路，構築防禦線。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"여기는 우리가 반드시 지켜낸......","JPN":"ここは我々が何としても守り……","ENG":"We must hold the line no matter—","TWN":"我們一定能守住這……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"이런 젠장! 큰형님이 쓰러졌다!","JPN":"クソッ！　兄貴が倒れたぞ！","ENG":"Drat! He's down!","TWN":"該死！大哥倒下了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"침식체 놈들, 갑자기 어디서 튀어나온 거야?","JPN":"侵食体どもめ！　急にどこから出てきやがったんだ？","ENG":"Where did those C.O.s come from?","TWN":"這些侵蝕體是突然從哪裡冒出來的？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L3_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"땅 속에서 튀어나온 것 같습니다! 어떡하죠?","JPN":"土の中から飛び出したようです！　どうしましょう？","ENG":"I think they popped out of the ground! What should we do?","TWN":"好像是從地底出來的！怎麼辦？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"너흰 여기서 엄호사격이나 해! 형님은 내가 구해 온다!","JPN":"お前らはここで援護射撃を！　兄貴は私が救出する！","ENG":"You guys stay here and provide cover! I'll go save the big man!","TWN":"你在這裡做掩護！我去救大哥！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"크으윽......","JPN":"くううっ……","ENG":"Ngh...","TWN":"呃啊啊……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"정신 차리십쇼, 형님!","JPN":"気をしっかり、兄貴！","ENG":"Wake up, sir!","TWN":"快醒醒，大哥！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"제일 먼저 들어간다는 게 시체포대는 아니지 않습니까!","JPN":"真っ先に突入するのは納体袋のことじゃないでしょう！","ENG":"By \\"going in first,\\" you didn't mean going in a body bag, did you?","TWN":"這戰鬥還很長呢，可不能現在就涼掉了啊！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"쿨럭, 쿨럭!","JPN":"ゲホッ！　ゲホッ！","ENG":"*Cough, cough*","TWN":"咳咳，咳咳！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"당연히 아니지, 이 자식아......!","JPN":"当たり前だろ、クソ……！","ENG":"Of course not, you numbskull!","TWN":"當然，你這傢伙……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"두 번째 공격이 온다! 저건 내가 막을 테니 다들 엄폐해!","JPN":"また攻撃してくる！　あれは私が止めるから全員隠れろ！","ENG":"A second wave, incoming! I'll hold them off. Everyone take cover!","TWN":"第二波攻擊來了！我來抵擋，大家注意隱匿！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"형님! 방패 하나로는 무리입니다!","JPN":"兄貴！　盾一つじゃ無理です！","ENG":"Sir! You can't do that with just a shield!","TWN":"大哥！只靠一個盾牌擋不住啊！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......소빈아!","JPN":"……コハル！","ENG":"Sobin!","TWN":"……素蘋！"},"stage":{"bg":"MAINSTREAM_6100017","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"응! 알았어, 대장!","JPN":"うん！　わかった、隊長！","ENG":"Yup! Got it, Cap!","TWN":"是！收到，隊長！"},"stage":{"bg":"MAINSTREAM_6100017","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"저, 저기......! 그러니까...... 머리 조심하세요!!","JPN":"あ、あの……！　えーと……頭に気をつけてください！！","ENG":"U-um... So... Watch your heads!","TWN":"那邊的人……！要……小心頭部！！"},"stage":{"bg":"MAINSTREAM_6100017","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 후방에 있는 포병대에서 지원 사격이라도 한 건가?","JPN":"な、なんだ？　後方にいる砲兵隊が応援射撃でもしてくれたのか？","ENG":"W-what just happened? Did we get fire support from the rear artillery?","TWN":"怎、怎麼回事？難道是後方炮兵的支援射擊？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"아, 아닙니다!","JPN":"ち、違います！","ENG":"N-no, sir!","TWN":"不，好像不是！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"포병대가 아니라 저 여자애들이 쏜 거 같은데요?","JPN":"砲兵隊じゃなくてあの女の子たちが撃ったみたいです！","ENG":"It wasn't the artillery... I think it was those girls!","TWN":"不是炮兵，好像是那邊的女孩子們發射的？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"말이 되는 소릴 해! 여자애들이 미사일 포대를 짊어지고 다니는 것도 아니고......!","JPN":"バカ言うな！　女の子じゃミサイル砲台を持ち運ぶことすらできないだろ……！","ENG":"Don't be ridiculous! Have you ever seen any girls carrying missile launchers around—","TWN":"別開玩笑了！難道女孩子們背著導彈發射器……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"아니, 잠깐.","JPN":"いや、待てよ。","ENG":"Hang on.","TWN":"不，等一下。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"저 아가씨들...... 혹시 카운터인가?","JPN":"あの子たち……もしかしてカウンターか？","ENG":"Those young ladies... Could they be Counters?","TWN":"難道說……那邊的女孩子是制裁者？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"함교. 여기는 코핀 컴퍼니 제 2 유격 소대 알트.","JPN":"艦橋。こちらコフィンカンパニー第2遊撃小隊アルト。","ENG":"Come in, Bridge. This is the 2nd Commando Squad of Coffin Company, ALT.","TWN":"艦橋。這裡是科芬公司第2遊擊小隊，阿爾特。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"긴급 강하 성공, 작전 지역에 도착했습니다.","JPN":"急降下成功、作戦地域に到着しました。","ENG":"Airborne insertion successful. We are at the AO.","TWN":"緊急降落成功，已到達作戰地區。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"목표인 제 3종 침식체 확인.","JPN":"ターゲットの第3種侵食体確認。","ENG":"We have eyes on the objective: Category 3 C.O.","TWN":"確認目標為第3類侵蝕體。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"전달받은 대로 지금부터 침식체 유인 작전을 개시합니다.","JPN":"伝達内容どおり、今から侵食体の誘引作戦を開始します。","ENG":"We're now commencing operation to lure the C.O. out, as instructed.","TWN":"根據指示，現在開始侵蝕體引誘作戰。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"확인했습니다, 서윤 소대장. 행운을 빕니다.","JPN":"確認しました、アオイ・シズカ小隊長。幸運を祈ります。","ENG":"Copy that, Commander Seo Yoon. Good luck.","TWN":"收到，徐芸小隊長。祝你成功。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......오랜만의 실전이야. 다들 준비됐지?","JPN":"……久しぶりの実戦ね。みんな、準備はいい？","ENG":"It's been a while since we've been on the field. Everyone ready?","TWN":"……好久沒進行實戰了。都準備好了嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"당연하지! 몸이 근질근질해서 혼났다고!","JPN":"もちろんだ！　体がうずうずしてきたぞ！","ENG":"Of course! I've been itching for some real action!","TWN":"當然了！早就迫不及待了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"지원 사격은 내게 맡겨. 대장 근처에는 한 놈도 못 오게 막을 테니까.","JPN":"援護射撃なら任せて。隊長の周りに敵は一匹も近付かせないから。","ENG":"You can count on me for sniper support. I won't let any of those C.O.s get near you.","TWN":"我來支援射擊。我不會讓敵人靠近隊長身邊的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"좋아, 그럼 간다!","JPN":"よし、いくよ！","ENG":"Sounds good. Here we go then!","TWN":"好，那就開始吧！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};